SELECT AVG(md.market_cap) as average_market_cap
FROM market_data md
WHERE md.timestamp >= DATE('now', '-30 days') AND md.market_cap > 1000000000;

external_knowledge:
- 'top' refers to the highest trading volume in USD; 
- 'over the last 24 hours' means the time range is from the current time minus 24 hours to the current time; 
- 'market capitalization ranks' are calculated based on the cumulative distribution of the market capitalization across all symbols.
